namespace CreditCardApi.Domain.Entities;

/// <summary>
/// A purchase charged against a <see cref="Entities.CreditCard"/>.
/// </summary>
public class Transaction
{
    /// <summary>Surrogate primary key, generated by the database.</summary>
    public int Id { get; set; }

    /// <summary>Foreign key to the owning <see cref="Entities.CreditCard"/>. Required.</summary>
    public int CreditCardId { get; set; }

    /// <summary>Navigation to the owning card.</summary>
    public CreditCard? CreditCard { get; set; }

    /// <summary>Amount charged. Always strictly positive, stored with two decimal places.</summary>
    public decimal Amount { get; set; }

    /// <summary>Merchant where the purchase was made. Required, non-empty.</summary>
    public string Merchant { get; set; } = string.Empty;

    /// <summary>Free-form spending category, e.g. <c>shopping</c>. Optional.</summary>
    public string? Category { get; set; }

    /// <summary>UTC timestamp assigned by the server when the transaction was created.</summary>
    public DateTime CreatedAt { get; set; }
}
